import React, { FC } from "react";
import { red } from "../../../../../assets/colors";

type MaintenanceContainerProps = {
  title: string;
};

const MaintenanceContainer: FC<MaintenanceContainerProps> = (props) => {
  const { title, children } = props;
  return (
    <div
      style={{
        width: "98vw",
        height: 300,
        padding: "1em",
        display: "flex",
        flexDirection: "row",
        alignItems: "flex-start",
        borderRadius: "3vw",
        borderWidth: "0.1vw",
        borderColor: "black",
        borderStyle: "solid",
        margin: "1vh",
      }}
    >
      <div
        style={{ display: "flex", flexDirection: "row", alignItems: "center" }}
      >
        <div
          style={{
            backgroundColor: red,
            borderRadius: "3em",
            color: "#fff",
            padding: "0.8em",
            display: "block",
            fontWeight: "bold",
            fontSize: 14,
          }}
        >
          {title}
        </div>
      </div>
      {children}
    </div>
  );
};

export default MaintenanceContainer;
